import{_ as a,c as i,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Приложение opencode-notify: Полный справочник по типам событий и файлам конфигурации | Учебник","description":"Справочник по типам событий плагина opencode-notify и примерам файлов конфигурации. В этом руководстве перечислены четыре типа событий OpenCode с их условиями срабатывания, детально объясняются фильтрационные правила для каждого события и различия между платформами, предоставляется полный шаблон файла конфигурации, детальные комментарии для всех полей конфигурации, настройки по умолчанию, примеры минимальной конфигурации, способы отключения плагина, а также полный список доступных звуков macOS.","frontmatter":{"title":"Приложение opencode-notify: Полный справочник по типам событий и файлам конфигурации | Учебник","sidebarTitle":"Справочник по конфигурации и событиям","subtitle":"Приложение: Справочник по типам событий и конфигурации","description":"Справочник по типам событий плагина opencode-notify и примерам файлов конфигурации. В этом руководстве перечислены четыре типа событий OpenCode с их условиями срабатывания, детально объясняются фильтрационные правила для каждого события и различия между платформами, предоставляется полный шаблон файла конфигурации, детальные комментарии для всех полей конфигурации, настройки по умолчанию, примеры минимальной конфигурации, способы отключения плагина, а также полный список доступных звуков macOS.","order":5},"headers":[],"relativePath":"ru/kdcokenny/opencode-notify/appendix/index.md","filePath":"ru/kdcokenny/opencode-notify/appendix/index.md"}'),l={name:"ru/kdcokenny/opencode-notify/appendix/index.md"};function n(r,e,d,s,c,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="приложение-справочник-по-типам-событии-и-конфигурации" tabindex="-1">Приложение: Справочник по типам событий и конфигурации <a class="header-anchor" href="#приложение-справочник-по-типам-событии-и-конфигурации" aria-label="Permalink to &quot;Приложение: Справочник по типам событий и конфигурации&quot;">​</a></h1><p>Этот раздел содержит справочную документацию и примеры конфигурации, которые помогут вам глубоко понять типы событий и параметры конфигурации плагина opencode-notify. Этот материал предназначен для справки и не требует последовательного изучения.</p><h2 id="учебныи-путь" tabindex="-1">Учебный путь <a class="header-anchor" href="#учебныи-путь" aria-label="Permalink to &quot;Учебный путь&quot;">​</a></h2><h3 id="_1-типы-событии" tabindex="-1">1. <a href="./event-types/">Типы событий</a> <a class="header-anchor" href="#_1-типы-событии" aria-label="Permalink to &quot;1. [Типы событий](./event-types/)&quot;">​</a></h3><p>Узнайте о типах событий OpenCode, которые отслеживает плагин, и об условиях их срабатывания.</p><ul><li>Четыре типа событий (session.idle, session.error, permission.updated, tool.execute.before)</li><li>Условия срабатывания и логика обработки для каждого типа событий</li><li>Фильтрационные правила: проверка родительской сессии, проверка тихих часов, проверка фокуса терминала</li><li>Различия в функциональности на разных платформах</li></ul><h3 id="_2-пример-фаила-конфигурации" tabindex="-1">2. <a href="./config-file-example/">Пример файла конфигурации</a> <a class="header-anchor" href="#_2-пример-фаила-конфигурации" aria-label="Permalink to &quot;2. [Пример файла конфигурации](./config-file-example/)&quot;">​</a></h3><p>Ознакомьтесь с полным примером файла конфигурации и детальными комментариями ко всем полям.</p><ul><li>Полный шаблон файла конфигурации</li><li>Описание полей notifyChildSessions, sounds, quietHours, terminal и других</li><li>Полный список доступных звуков для macOS</li><li>Пример минимальной конфигурации</li><li>Способы отключения плагина</li></ul><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендация по изучению</p><p>Этот раздел является справочной документацией, к которой можно обращаться по необходимости. Рекомендуется изучить материалы этого раздела после завершения следующих базовых учебников:</p><ul><li><a href="./../../start/quick-start/">Быстрое начало</a> — завершение установки и базовой конфигурации</li><li><a href="./../../start/how-it-works/">Как это работает</a> — понимание основных механизмов плагина</li></ul></div><h2 id="дальнеишие-шаги" tabindex="-1">Дальнейшие шаги <a class="header-anchor" href="#дальнеишие-шаги" aria-label="Permalink to &quot;Дальнейшие шаги&quot;">​</a></h2><p>После изучения материалов приложения вы можете:</p><ul><li>Просмотреть <a href="./../changelog/release-notes/">Журнал изменений</a> для знакомства с историей версий и новыми функциями</li><li>Вернуться к <a href="./../../advanced/config-reference/">Справочнику по конфигурации</a> для глубокого изучения расширенных параметров конфигурации</li><li>Изучить <a href="./../../faq/common-questions/">Часто задаваемые вопросы</a> для поиска ответов</li></ul>',14)])])}const u=a(l,[["render",n]]);export{f as __pageData,u as default};
